-- All "Solo"-category trips (Fabian only), consolidated into one file for
-- easier reading/maintenance. Replaces the following, now-deleted files
-- (each trip's data below is the final state after every correction that
-- used to live across them, applied in order):
--   add_solo_slovakia_trip.sql, add_solo_trips_2.sql, fix_iberia_route.sql,
--   add_solo_istanbul_trip.sql, add_solo_grand_tour_trip.sql,
--   fix_solo_trips_3.sql
--
-- IMPORTANT: every trip below already exists in the live database — this
-- file documents the current, correct state, it is NOT meant to be run
-- against the current DB (it would create duplicates of everything). Keep
-- it as the single source of truth to read/diff against when a trip needs
-- another correction, and only actually execute it if setting up a fresh
-- database from scratch (e.g. disaster recovery).
--
-- Travel mode note: the enum only distinguishes rail (train) from road
-- (car) — bus legs are mapped to 'car' as the closest fit.
--
-- The four route_geometry values at the end are real transit-network paths
-- from Transitous (transitous.org), hand-picked to match the actual
-- historical route/border-crossing rather than whichever itinerary the
-- general backfill script (scripts/backfill-route-geometry.mjs) picks as
-- "fastest today". If that script is ever re-run with FORCE=1, it will
-- overwrite these four with its generic pick again — re-apply the four
-- UPDATEs at the bottom of this file afterward if so.

do $$
#variable_conflict use_variable
declare
  admin_id uuid;
  trip_id uuid;
begin
  select id into admin_id from profiles where email = 'fabian.joebstl@gmail.com';
  if admin_id is null then
    raise exception 'No profile found for fabian.joebstl@gmail.com — sign in once first, then re-run this.';
  end if;

  -- ── 2021: Grand Tour ────────────────────────────────────────────────────
  insert into trips (title, year, status, dates_confirmed, color, description, category, created_by)
